  records.filter(r => r.type === 'Stage').forEach(r => console.log(' ', (r.result||r.state).padEnd(12), r.name));
  console.log('\n=== ALL JOBS ===');
  records.filter(r => r.type === 'Job').forEach(r => console.log(' ', (r.result||r.state).padEnd(12), r.name));
